import{_ as e,o as i,c as t,a3 as o}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"XiHan.Framework.Tasks","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/tasks.md","filePath":"cosmos/framework/packages/tasks.md","lastUpdated":1783216089000}'),s={name:"cosmos/framework/packages/tasks.md"};function r(d,a,n,l,c,h){return i(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="xihan-framework-tasks" tabindex="-1">XiHan.Framework.Tasks <a class="header-anchor" href="#xihan-framework-tasks" aria-label="Permalink to &quot;XiHan.Framework.Tasks&quot;">​</a></h1><blockquote><p>定时任务：调度引擎、后台服务、多租户感知。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Tasks</code></li><li><strong>模块类</strong>：<code>XiHanTasksModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Tasks 是框架的任务库，提供两类能力：一是<strong>定时任务调度</strong>（按 Cron、固定间隔或延迟触发一段业务逻辑），二是<strong>后台常驻服务基类</strong>（不断从队列/消息源拉取任务并并发处理）。它内置了一套自研的调度引擎与执行管道，任务执行时会自动带上当前租户上下文，天然适配多租户场景。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要按 Cron 表达式、固定时间间隔或一次性延迟运行的定时作业。</li><li>需要一个常驻后台服务，持续从 Redis/数据库/消息队列拉取并发处理任务。</li><li>希望任务执行自带日志、超时、锁、重试、指标等横切能力，而不必自己拼装。</li><li>多租户应用中，希望定时任务在正确的租户上下文里执行。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Tasks</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanTasksModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>AddXiHanTasks(config)</code>，从配置节 <code>XiHan:Tasks:ScheduledJobs</code>（<code>XiHanJobOptions.SectionName</code>）绑定选项，并注册调度器、执行器、中间件与托管服务。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>多触发方式调度</strong>：<code>CompositeJobScheduler</code> 支持 Cron、Interval（固定间隔）、Delay（一次性延迟）三种触发类型，内部每秒检查一次待触发任务。</li><li><strong>执行管道 + 中间件</strong>：任务通过 <code>JobExecutionPipeline</code> 逐层经过 Logging、Timeout、Lock、Retry、Metrics 等中间件（<code>IJobMiddleware</code>），横切能力可插拔、可自定义。</li><li><strong>后台服务基类</strong>：<code>XiHanBackgroundServiceBase&lt;T&gt;</code> 封装并发控制、队列拉取、异常重试、优雅停机与运行统计，子类只需实现「取任务」和「处理任务」两个方法。</li><li><strong>任务锁</strong>：<code>CachingJobLockProvider</code> 复用 Caching 模块的分布式锁（有 Redis 时跨实例、否则进程内回退），防止同一任务并发重入。</li><li><strong>多租户感知</strong>：调度时解析任务所属租户（参数 / JobInfo / 当前租户），执行时用 <code>ICurrentTenant.Change(...)</code> 切换到对应租户上下文再运行。</li><li><strong>声明式特性</strong>：通过 <code>[JobSchedule]</code>、<code>[JobName]</code>、<code>[JobRetry]</code>、<code>[JobTimeout]</code>、<code>[JobConcurrent]</code> 等特性描述任务，配合自动发现注册。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IJobScheduler</code> / <code>CompositeJobScheduler</code></td><td>调度器接口与复合实现，负责注册、暂停/恢复、手动触发、计算下次执行时间</td></tr><tr><td><code>IJobExecutor</code> / <code>JobExecutor</code></td><td>任务执行器，负责在租户上下文中运行任务实例</td></tr><tr><td><code>JobExecutionPipeline</code> / <code>IJobMiddleware</code></td><td>执行管道与中间件抽象，串联横切逻辑</td></tr><tr><td><code>IJobWorker</code> / <code>IJobContext</code></td><td>具体任务的实现契约与执行上下文</td></tr><tr><td><code>IJobStore</code> / <code>InMemoryJobStore</code></td><td>任务实例存储抽象与内存实现</td></tr><tr><td><code>IJobLockProvider</code> / <code>CachingJobLockProvider</code></td><td>任务锁抽象与基于 Caching 的实现</td></tr><tr><td><code>XiHanBackgroundServiceBase&lt;T&gt;</code></td><td>后台常驻服务基类（并发拉取消费）</td></tr><tr><td><code>XiHanJobBuilder</code> / <code>XiHanJobOptions</code></td><td>链式配置构建器与调度选项</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./caching">XiHan.Framework.Caching</a> — 任务锁复用其统一的分布式锁（Redis / 进程内自动选择）。</li><li><a href="./multitenancy">XiHan.Framework.MultiTenancy</a> 与 <a href="./multitenancy-abstractions">XiHan.Framework.MultiTenancy.Abstractions</a> — 任务的租户解析与执行期租户上下文切换。</li><li><a href="./timing">XiHan.Framework.Timing</a> — 时间基础设施。</li></ul><p>（Cron 解析、重试策略等由框架自身实现，未引入 Quartz/Cronos 等第三方调度库。）</p><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./caching">XiHan.Framework.Caching</a> — 分布式锁与缓存底座。</li><li><a href="./multitenancy">XiHan.Framework.MultiTenancy</a> — 多租户上下文来源。</li></ul>`,21)])])}const g=e(s,[["render",r]]);export{p as __pageData,g as default};
